var config2 = loadConfig();
var logger = new Logger(config2.logLevel);
startServer(config2).catch((error2) => {
  logger.log("error", "mcp_server_start_failed", { error: error2 instanceof Error ? error2.message : String(error2) });
  process.exit(1);
});
